// Dedup against existing pipeline — case-insensitive, strips legal suffixes
const norm = s => String(s || '').toLowerCase()
  .replace(/\b(llc|inc|corp|ltd|lp|llp|pllc|co\.|company|group|holdings|renewables|energy|power|data centers?|digital)\b/g, '')
  .replace(/[^a-z0-9]+/g, ' ').trim();
const existingSet = new Set(
  $input.all()
    .map(i => norm(i.json.fields?.fldLL2FMn3Y3KSG1z || i.json.fldLL2FMn3Y3KSG1z || ''))
    .filter(Boolean)
);
const JUNK = /^(unknown|undisclosed|multiple|various|several|tbd|n\/a)/i;
const signals = $('List Recent High Signals').all();
const seen = new Set();
const out = [];
for (const item of signals) {
  const f = item.json.fields || item.json;
  const company = String(f['Company'] || '').trim();
  if (!company || company.length < 3 || JUNK.test(company)) continue;
  const key = norm(company);
  if (!key || existingSet.has(key) || seen.has(key)) continue;
  seen.add(key);
  out.push({
    json: {
      signal_id: item.json.id,
      signal_company: company,
      signal_type: (f['Signal Type']?.name || f['Signal Type'] || ''),
      signal_detail: (f['Signal Detail'] || ''),
      signal_location: (f['Location'] || ''),
      signal_outreach_angle: (f['Outreach Angle'] || ''),
      signal_score: (f['Signal Score']?.name || f['Signal Score'] || f['Score'] || ''),
      signal_mw: (f['MW Size'] || ''),
      actionability: (f['Actionability'] || ''),
      actionability_rationale: (f['Actionability Rationale'] || '')
    }
  });
}
return out.slice(0, 5);

// Merge signal data (input 0) with Claude parsed output (input 1)
const signalItems = $input.all();
const claudeItems = $('Claude — Identify Need + Draft DM').all();

const out = [];

for (let i = 0; i < signalItems.length; i++) {
  const signal = signalItems[i]?.json || {};
  const claudeRaw = claudeItems[i]?.json || {};

  // Parse Claude response
  const raw = claudeRaw.content?.find(b => b.type === 'text')?.text
    || claudeRaw.content?.[claudeRaw.content.length - 1]?.text || '';

  let parsed = {};
  try {
    parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch(e) {
    const m = raw.match(/\{[\s\S]*\}/);
    try { parsed = m ? JSON.parse(m[0]) : {}; } catch { parsed = {}; }
  }

  // Merge — signal fields take base, Claude adds enrichment
  out.push({
    json: {
      // From signal
      signal_id:       signal.signal_id       || '',
      signal_company:  signal.signal_company   || '',
      signal_type:     signal.signal_type      || '',
      signal_detail:   signal.signal_detail    || '',
      signal_location: signal.signal_location  || '',
      signal_mw:       signal.signal_mw        || '',
      // From Claude
      contact_name:    parsed.contact_name     || '',
      target_title:    parsed.target_title     || '',
      linkedin_url:    parsed.linkedin_url     || '',
      email:           parsed.email            || '',
      project_need:    parsed.project_need     || '',
      service_match:   parsed.service_match    || '',
      signal_hook:     parsed.signal_hook      || signal.signal_outreach_angle || signal.signal_detail || '',
      draft_message:   parsed.draft_message    || '',
      research_notes:  parsed.research_notes   || '',
      actual_title:    parsed.actual_title     || '',
      enrichment_status: parsed.enrichment_status || 'Needs Clay',
      data_source:     parsed.data_source      || 'Web Search'
    }
  });
}

return out;

// Field IDs (Outreach Pipeline) — write by ID to avoid name drift.
const F = {
  contact: 'fldAYJfmDu3g1yuDX', title: 'fldumu5th7aPdxgoF', company: 'fldLL2FMn3Y3KSG1z',
  linkedin: 'fldaq7M5Jz1LUp0lv', email: 'fldnBwIqMSYS577Ki', hook: 'fldJK3FAM4mPvhnDw',
  draft: 'fldn6imsWP0eiq29R', channel: 'fldDHjKyHP1XEseyg', status: 'fldTaGWpuRTmnG8yG',
  notes: 'fldI0EvZPGm9XrwWz', source: 'fldjSrdlhrORN6xyP', enrStatus: 'fldCXm7kgxLUKzgNL',
  dataSrc: 'fld4ayILRKw9aYWux', enrDate: 'fldB5qbGXxGWIEL2T'
};
const today = new Date().toISOString().slice(0, 10);
const items = [];
for (const it of $input.all()) {
  const d = it.json;
  const v = x => (x == null ? '' : ('' + x)).trim();
  const contact = v(d.contact_name);
  const verifiedTitle = v(d.actual_title);
  const title = verifiedTitle || v(d.target_title);
  const linkedin = v(d.linkedin_url);
  const email = v(d.email);
  const company = v(d.signal_company);

  const missing = [];
  if (!email) missing.push('Email');
  if (!verifiedTitle) missing.push('Title');
  if (!linkedin) missing.push('LinkedIn URL');

  const hasContactPath = !!(linkedin || email);
  let enrStatus, dataSource;
  if (!hasContactPath) { enrStatus = 'Needs Clay'; dataSource = 'Web Search'; }
  else if (email) { enrStatus = 'Web Enriched'; dataSource = 'Web Search'; }
  else { enrStatus = 'Needs Clay'; dataSource = 'Web Search'; }

  const rec = {};
  rec[F.contact]   = contact;
  rec[F.title]     = title;
  rec[F.company]   = company;
  rec[F.linkedin]  = linkedin;
  rec[F.email]     = email;
  rec[F.hook]      = v(d.signal_hook) || v(d.signal_outreach_angle) || v(d.signal_detail);
  rec[F.draft]     = v(d.draft_message);
  rec[F.channel]   = 'LinkedIn DM';
  rec[F.notes]     = [
    v(d.project_need) ? 'NEED: ' + v(d.project_need) : '',
    v(d.service_match) ? 'SERVICE MATCH: ' + v(d.service_match) : '',
    v(d.research_notes) ? 'RESEARCH: ' + v(d.research_notes) : '',
    missing.length ? 'Missing: ' + missing.join(', ') : ''
  ].filter(Boolean).join('\n\n');
  rec[F.enrStatus] = enrStatus;
  rec[F.dataSrc]   = dataSource;
  rec[F.enrDate]   = today;
  rec[F.status]    = 'New Lead';
  // Flag P1 with draft as Follow Up immediately
  if (rec[F.draft] && rec[F.draft].length > 20) {
    rec[F.status] = 'Follow Up';
  }
  if (v(d.signal_id)) rec[F.source] = [v(d.signal_id)];
  items.push({ json: rec });
}
return items;
